(function(){if(window.btdt&&window.btdt._initialized)return;const script=document.currentScript;if(!script)return;const initialPreset=script.getAttribute('data-preset');const autoInit=script.getAttribute('data-auto-init')!=='false';const detectedBase=script.src.split('/').slice(0,-2).join('/')+'/';const basePath=script.getAttribute('data-base-path')||detectedBase;const linkId='theme-preset';let existingLink=document.getElementById(linkId);if(!existingLink){existingLink=Array.from(document.querySelectorAll('link[rel="stylesheet"]')).find(link=>link.href.includes('themes/preset/'));if(existingLink)existingLink.id=linkId;}
if(initialPreset&&!existingLink){const link=document.createElement('link');link.id=linkId;link.rel='stylesheet';link.href=initialPreset.endsWith('.css')?initialPreset:`${basePath}themes/preset/${initialPreset}.css`;document.head.appendChild(link);}
window.btdt={_initialized:true,_manager:null,_loading:null,getManager:function(){if(this._manager)return Promise.resolve(this._manager);if(this._loading)return this._loading;this._loading=new Promise((resolve)=>{const s=document.createElement('script');s.src=`${basePath}js/theme-manager.js`;s.onload=()=>{this._manager=new ThemeManager({basePath});resolve(this._manager);};document.head.appendChild(s);});return this._loading;},load:async function(name){const m=await this.getManager();return m.applyPreset(name);},toggleMode:async function(){const m=await this.getManager();return m.toggleMode();},setMode:async function(mode){const m=await this.getManager();return m.setMode(mode);}};if(autoInit){window.btdt.getManager();}})();